import { memo, Suspense, lazy, useState, useRef } from "react";
import { FiExternalLink, FiChevronRight } from "react-icons/fi";
import SmartImage from "../SmartImage";
import EngagementBar from "../EngagementBar";
import { timeAgo } from "../../../lib/feed/formatTime";

const NewsArticleModal = lazy(() => import("../NewsArticleModal"));

/**
 * NewsCard — club-branded article card. The description is shown as a MANUAL
 * (scroll-snap) slider of paragraphs, ending on a slide with a source link and
 * a swipe icon. Falls back to an Open link when there's no body text.
 */
function NewsCard({ item, onComment, onShare, onReport }) {
  const { article } = item;
  const [open, setOpen] = useState(false);
  const hasFullArticle =
    Array.isArray(article.article) && article.article.length > 0;
  const club = article.club;
  const slides = (hasFullArticle ? article.article : article.summary) || [];
  const totalSlides = slides.length + (article.link ? 1 : 0);

  const sliderRef = useRef(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);
  const [hasDragged, setHasDragged] = useState(false);

  const handlePointerDown = (e) => {
    if (e.pointerType !== "mouse") return;
    if (!sliderRef.current) return;
    setIsDragging(true);
    setHasDragged(false);
    setStartX(e.pageX - sliderRef.current.offsetLeft);
    setScrollLeft(sliderRef.current.scrollLeft);
    try {
      sliderRef.current.setPointerCapture(e.pointerId);
    } catch (err) {}
  };

  const handlePointerUp = (e) => {
    if (e.pointerType !== "mouse") return;
    setIsDragging(false);
    try {
      if (sliderRef.current && sliderRef.current.hasPointerCapture(e.pointerId)) {
        sliderRef.current.releasePointerCapture(e.pointerId);
      }
    } catch (err) {}
  };

  const handlePointerMove = (e) => {
    if (!isDragging || !sliderRef.current || e.pointerType !== "mouse") return;
    setHasDragged(true);
    const x = e.pageX - sliderRef.current.offsetLeft;
    const walk = (x - startX) * 2;
    sliderRef.current.scrollLeft = scrollLeft - walk;
  };

  const openArticle = () => {
    if (hasFullArticle) setOpen(true);
    else if (article.link)
      window.open(article.link, "_blank", "noopener,noreferrer");
  };

  return (
    <article className="cf-card cf-news2">
      <header className="cf-card-head">
        <span className="cf-avatar">
          <SmartImage
            src={article.sourceImg}
            alt={article.source}
            label={article.source}
            contain
          />
        </span>
        <div className="cf-head-meta">
          <span className="cf-source">{article.source}</span>
        </div>
      </header>

      <div className="cf-news2-body">
        <div className="cf-news2-panel">
          {club && (club.name || club.image) && (
            <div className="cf-news2-club">
              <span className="cf-news2-crest">
                <SmartImage
                  src={club.image}
                  alt={club.name}
                  label={club.name}
                  contain
                />
              </span>
              <span className="cf-news2-clubname">{club.name}</span>
            </div>
          )}

          <div className="cf-news2-byline">
            {article.sourceImg && (
              <span className="cf-news2-byic">
                <SmartImage
                  src={article.sourceImg}
                  alt=""
                  label={article.source}
                  contain
                />
              </span>
            )}
            <span className="cf-news2-by">
              {article.source}
              {article.createdAt
                ? ` · ${timeAgo(article.timestamp, article.createdAt)}`
                : ""}
            </span>
          </div>

          <div className="cf-news2-main">
            <button
              type="button"
              className="cf-news2-titlebtn"
              onClick={openArticle}
            >
              <h3 className="cf-news2-title">{article.title}</h3>
            </button>
            {article.image && (
              <button
                type="button"
                className="cf-news2-thumb"
                onClick={openArticle}
                aria-label="Open article"
              >
                <SmartImage
                  src={article.image}
                  alt={article.title}
                  label={article.source}
                />
              </button>
            )}
          </div>

          {slides.length > 0 ? (
            <div
              ref={sliderRef}
              className={`cf-news2-slider ${isDragging ? "dragging" : ""}`}
              role="group"
              aria-label="Article summary"
              onPointerDown={handlePointerDown}
              onPointerUp={handlePointerUp}
              onPointerCancel={handlePointerUp}
              onPointerMove={handlePointerMove}
              onDragStart={(e) => e.preventDefault()}
            >
              {slides.map((para, i) => (
                <div className="cf-news2-slide" key={i}>
                  <p className="cf-news2-slidetext">{para}</p>
                  <span className="cf-news2-slidenum">
                    {i + 1}/{totalSlides}
                  </span>

                  <span className="swiper_icon_container">
                    <span className="swiper_icon_text">
                      <span className="swiper_text">Swipe</span>
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        xmlns:xlink="http://www.w3.org/1999/xlink"
                        width="331"
                        height="280"
                        viewBox="0 0 331 280"
                        fill="none"
                      >
                        <rect
                          width="331"
                          height="280"
                          fill="url(#pattern0_3146_76)"
                        ></rect>
                        <defs>
                          <pattern
                            id="pattern0_3146_76"
                            patternContentUnits="objectBoundingBox"
                            width="1"
                            height="1"
                          >
                            <use
                              xlink:href="#image0_3146_76"
                              transform="scale(0.000508672 0.000601323)"
                            ></use>
                          </pattern>
                          <image
                            id="image0_3146_76"
                            width="1966"
                            height="1663"
                            preserveAspectRatio="none"
                            xlink:href="data:image/png;base64,"
                          ></image>
                        </defs>
                      </svg>
                    </span>

                    <span className="swiper_paginations">
                      {Array.from({ length: totalSlides }).map((_, dotIdx) => (
                        <span
                          key={dotIdx}
                          className={`swiper_pagi ${i === dotIdx ? "active" : ""}`}
                        ></span>
                      ))}
                    </span>
                  </span>
                </div>
              ))}
              {article.link && (
                <a
                  className="cf-news2-slide cf-news2-slide-end"
                  href={article.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  onClick={(e) => {
                    if (hasDragged) e.preventDefault();
                  }}
                >
                  <FiExternalLink size={20} />
                  <span className="cf-news2-endtext">
                    Read the full story at {article.source}
                  </span>
                  <span className="cf-news2-swipe">
                    <FiChevronRight size={18} />
                  </span>
                </a>
              )}
            </div>
          ) : (
            (article.link || hasFullArticle) && (
              <button
                type="button"
                className="cf-news2-link"
                onClick={openArticle}
              >
                <FiExternalLink size={13} />{" "}
                {hasFullArticle ? "Read more" : "Open link"}
              </button>
            )
          )}
        </div>
      </div>

      <EngagementBar
        id={article.id}
        dedupeId={item.dedupeId}
        initialLikes={item.eng?.like_count}
        initialComments={item.eng?.comment_count}
        initialShares={item.eng?.share_count}
        initialLiked={item.eng?.liked}
        saveSnapshot={{
          kind: "news",
          title: article.title,
          image: article.image,
          source: article.source,
          link: article.link,
          timestamp: article.timestamp,
        }}
        onComment={onComment}
        onShare={onShare}
        onReport={onReport}
      />

      {open && (
        <Suspense fallback={null}>
          <NewsArticleModal article={article} onClose={() => setOpen(false)} />
        </Suspense>
      )}
    </article>
  );
}

export default memo(NewsCard);
